# @cctt_verify {"v":2,"sym":"sympy.tensor.tests.test_indexed.test_differentiation","kind":"function","src_hash":"276e5cb2519fc1b3","in":{"base":"Any"},"out":{"base":"Any","pred":"m.is_real and expr.diff(hj) == KroneckerDelta(i, j) and expr.diff(hi) == KroneckerDelta(i, i) and expr.diff(hj) == S(2) * KroneckerDelta(i, j) and expr.diff(hi) == S(2) * KroneckerDelta(i, i) and expr.diff(a) is S.Zero and Sum(expr, (i, -oo, oo)).diff(hj) == Sum(2 * KroneckerDelta(i, j), (i, -oo, oo)) and Sum(expr.diff(hj), (i, -oo, oo)) == Sum(2 * KroneckerDelta(i, j), (i, -oo, oo)) and Sum(expr, (i, -oo, oo)).diff(hj).doit() == 2 and Sum(expr.diff(hi), (i, -oo, oo)).doit() == Sum(2, (i, -oo, oo)).doit() and Sum(expr, (i, -oo, oo)).diff(hi).doit() is oo and expr.diff(hi) == a * h[j] * KroneckerDelta(i, j) and expr.diff(a) == hj * hj / S(2) and expr.diff(a, 2) is S.Zero and Sum(expr, (i, -oo, oo)).diff(hi).doit() == a * h[j] and Sum(expr, (j, -oo, oo)).diff(hi).doit() == a * h[i] and expr.diff(hi) == 2 * a * cos(hj * hj) * hj * KroneckerDelta(i, j) and expr.diff(hj) == 2 * a * cos(hj * hj) * hj and expr.diff(hi) == a * L[i, j] * KroneckerDelta(i, j) and expr.diff(hj) == a * L[i, j] and expr.diff(L[i, j]) == a * h[j] and expr.diff(L[k, l]) == a * KroneckerDelta(i, k) * KroneckerDelta(j, l) * h[j] and expr.diff(L[i, l]) == a * KroneckerDelta(j, l) * h[j] and Sum(expr, (j, -oo, oo)).diff(L[k, l]).doit() == a * KroneckerDelta(i, k) * h[l] and h[m].diff(h[m]) == 1 and h[m].diff(h[n]) == KroneckerDelta(m, n) and Sum(a * h[m], (m, -oo, oo)).diff(h[n]).doit() == a and Sum(a * h[m], (m, -oo, oo)).diff(h[m]).doit() == oo * a"},"spec":{"lhs":"test_differentiation()","rhs":"test_differentiation produces the expected output","over":{"base":"Any"},"name":"test_differentiation_correct"},"guarantee":"test_differentiation produces the expected output","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.tensor.tests.test_indexed.test_differentiation_correct","statement":"Path(test_differentiation(x), test_differentiation produces the expected output)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"501515a22b975d43"}
def test_differentiation():
    from sympy.functions.special.tensor_functions import KroneckerDelta
    i, j, k, l = symbols('i j k l', cls=Idx)
    a = symbols('a')
    m, n = symbols("m, n", integer=True, finite=True)
    assert m.is_real
    h, L = symbols('h L', cls=IndexedBase)
    hi, hj = h[i], h[j]

    expr = hi
    assert expr.diff(hj) == KroneckerDelta(i, j)
    assert expr.diff(hi) == KroneckerDelta(i, i)

    expr = S(2) * hi
    assert expr.diff(hj) == S(2) * KroneckerDelta(i, j)
    assert expr.diff(hi) == S(2) * KroneckerDelta(i, i)
    assert expr.diff(a) is S.Zero

    assert Sum(expr, (i, -oo, oo)).diff(hj) == Sum(2*KroneckerDelta(i, j), (i, -oo, oo))
    assert Sum(expr.diff(hj), (i, -oo, oo)) == Sum(2*KroneckerDelta(i, j), (i, -oo, oo))
    assert Sum(expr, (i, -oo, oo)).diff(hj).doit() == 2

    assert Sum(expr.diff(hi), (i, -oo, oo)).doit() == Sum(2, (i, -oo, oo)).doit()
    assert Sum(expr, (i, -oo, oo)).diff(hi).doit() is oo

    expr = a * hj * hj / S(2)
    assert expr.diff(hi) == a * h[j] * KroneckerDelta(i, j)
    assert expr.diff(a) == hj * hj / S(2)
    assert expr.diff(a, 2) is S.Zero

    assert Sum(expr, (i, -oo, oo)).diff(hi) == Sum(a*KroneckerDelta(i, j)*h[j], (i, -oo, oo))
    assert Sum(expr.diff(hi), (i, -oo, oo)) == Sum(a*KroneckerDelta(i, j)*h[j], (i, -oo, oo))
    assert Sum(expr, (i, -oo, oo)).diff(hi).doit() == a*h[j]

    assert Sum(expr, (j, -oo, oo)).diff(hi) == Sum(a*KroneckerDelta(i, j)*h[j], (j, -oo, oo))
    assert Sum(expr.diff(hi), (j, -oo, oo)) == Sum(a*KroneckerDelta(i, j)*h[j], (j, -oo, oo))
    assert Sum(expr, (j, -oo, oo)).diff(hi).doit() == a*h[i]

    expr = a * sin(hj * hj)
    assert expr.diff(hi) == 2*a*cos(hj * hj) * hj * KroneckerDelta(i, j)
    assert expr.diff(hj) == 2*a*cos(hj * hj) * hj

    expr = a * L[i, j] * h[j]
    assert expr.diff(hi) == a*L[i, j]*KroneckerDelta(i, j)
    assert expr.diff(hj) == a*L[i, j]
    assert expr.diff(L[i, j]) == a*h[j]
    assert expr.diff(L[k, l]) == a*KroneckerDelta(i, k)*KroneckerDelta(j, l)*h[j]
    assert expr.diff(L[i, l]) == a*KroneckerDelta(j, l)*h[j]

    assert Sum(expr, (j, -oo, oo)).diff(L[k, l]) == Sum(a * KroneckerDelta(i, k) * KroneckerDelta(j, l) * h[j], (j, -oo, oo))
    assert Sum(expr, (j, -oo, oo)).diff(L[k, l]).doit() == a * KroneckerDelta(i, k) * h[l]

    assert h[m].diff(h[m]) == 1
    assert h[m].diff(h[n]) == KroneckerDelta(m, n)
    assert Sum(a*h[m], (m, -oo, oo)).diff(h[n]) == Sum(a*KroneckerDelta(m, n), (m, -oo, oo))
    assert Sum(a*h[m], (m, -oo, oo)).diff(h[n]).doit() == a
    assert Sum(a*h[m], (n, -oo, oo)).diff(h[n]) == Sum(a*KroneckerDelta(m, n), (n, -oo, oo))
    assert Sum(a*h[m], (m, -oo, oo)).diff(h[m]).doit() == oo*a


